QActions.QAction:
using System;
using Newtonsoft.Json.Linq;
using Skyline.DataMiner.Scripting;

public class QAction
{
    public static void Run(SLProtocol protocol)
    {
        try
        {
            string json = protocol.GetParameter(11);

            if (String.IsNullOrEmpty(json))
                return;

            JArray streams = JArray.Parse(json);

            foreach (var stream in streams)
            {
                string channel = stream["channel"].ToString();
                double score = (double)stream["score"];
                string status = stream["status"].ToString();
                string timestamp = stream["timestamp"].ToString();

                int alarmState = 0;

                if (status == "LOGO_PRESENT")
                    alarmState = 0;

                else if (status == "LOGO_MAYBE_MISSING")
                    alarmState = 1;

                else if (status == "LOGO_MISSING")
                    alarmState = 2;

                protocol.SetRow(1000, channel, new object[]
                {
                    channel,
                    score,
                    status,
                    timestamp,
                    alarmState
                });
            }
        }
        catch (Exception ex)
        {
            protocol.Log("Logo parser error: " + ex.Message, LogType.Error, LogLevel.NoLogging);
        }
    }
}
